namespace sv_a548cd54b1c74a2596035e199166d314.Client.Auth;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_a548cd54b1c74a2596035e199166d314.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that reads persisted user info
/// from PersistentComponentState (serialized by the server during prerendering).
/// This ensures auth state survives the transition to WebAssembly.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Email),
                new(ClaimTypes.Email, userInfo.Email),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, authenticationType: "PersistentAuth");
            _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_a548cd54b1c74a2596035e199166d314.Client.Auth;

namespace sv_a548cd54b1c74a2596035e199166d314.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that:
/// 1. Returns a hardcoded authenticated user (bob@example.com with User/Editor roles).
/// 2. Persists the user info into PersistentComponentState so the client-side
///    provider can reconstruct the identity after WebAssembly activates.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        _subscription = persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);

        // Hardcoded authenticated user
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var principal = new ClaimsPrincipal(identity);
        _authStateTask = Task.FromResult(new AuthenticationState(principal));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => _authStateTask ?? Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirstValue(ClaimTypes.Email) ?? principal.Identity.Name ?? "";
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

