@page "/profile"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <p><strong>Roles:</strong></p>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == System.Security.Claims.ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor Page</h1>

<p>Welcome to the editor area. You have the Editor role.</p>

@page "/viewer"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer Page</h1>

<p>This page is accessible to any authenticated user.</p>

